#ifdef __cplusplus
extern "C" {
#endif

#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <omp.h>

#define fp float

#define NUMBER_PAR_PER_BOX 100
#define NUMBER_THREADS 128
#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct
{
	fp x, y, z;
} THREE_VECTOR;

typedef struct
{
	fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str
{
	int x, y, z;
	int number;
	long offset;
} nei_str;

typedef struct box_str
{
	int x, y, z;
	int number;
	long offset;
	int nn;
	nei_str nei[26];
} box_str;

typedef struct par_str
{
	fp alpha;
} par_str;

typedef struct dim_str
{
	int cur_arg;
	int arch_arg;
	int cores_arg;
	int boxes1d_arg;
	long number_boxes;
	long box_mem;
	long space_elem;
	long space_mem;
	long space_mem2;
} dim_str;

void kernel_cpu(	par_str par_cpu,
					dim_str dim_cpu,
					box_str* box_cpu,
					FOUR_VECTOR* rv_cpu,
					fp* qv_cpu,
					FOUR_VECTOR* fv_cpu)
{
	int num_boxes = (int)dim_cpu.number_boxes;

	#pragma omp parallel for schedule(dynamic)
	for (int bx = 0; bx < num_boxes; bx++) {

		fp a2 = 2.0f * par_cpu.alpha * par_cpu.alpha;

		FOUR_VECTOR rA_shared[NUMBER_PAR_PER_BOX];
		FOUR_VECTOR rB_shared[NUMBER_PAR_PER_BOX];
		fp qB_shared[NUMBER_PAR_PER_BOX];

		int first_i = box_cpu[bx].offset;

		for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
			rA_shared[wtx] = rv_cpu[first_i + wtx];
		}

		for (int k = 0; k < (1 + box_cpu[bx].nn); k++) {
			int pointer;
			if (k == 0) {
				pointer = bx;
			} else {
				pointer = box_cpu[bx].nei[k-1].number;
			}

			int first_j = box_cpu[pointer].offset;

			for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
				rB_shared[wtx] = rv_cpu[first_j + wtx];
				qB_shared[wtx] = qv_cpu[first_j + wtx];
			}

			for (int wtx = 0; wtx < NUMBER_PAR_PER_BOX; wtx++) {
				for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
					fp r2 = rA_shared[wtx].v + rB_shared[j].v - DOT(rA_shared[wtx], rB_shared[j]);
					fp u2 = a2 * r2;
					fp vij = exp(-u2);
					fp fs = 2.0f * vij;

					THREE_VECTOR d;
					d.x = rA_shared[wtx].x - rB_shared[j].x;
					d.y = rA_shared[wtx].y - rB_shared[j].y;
					d.z = rA_shared[wtx].z - rB_shared[j].z;

					fp fxij = fs * d.x;
					fp fyij = fs * d.y;
					fp fzij = fs * d.z;

					fv_cpu[first_i + wtx].v += qB_shared[j] * vij;
					fv_cpu[first_i + wtx].x += qB_shared[j] * fxij;
					fv_cpu[first_i + wtx].y += qB_shared[j] * fyij;
					fv_cpu[first_i + wtx].z += qB_shared[j] * fzij;
				}
			}
		}
	}
}

#ifdef __cplusplus
}
#endif
